[tool_use Bash] {"command": "cd /tmp && for v in 0.2 0.2.1 0.3 0.4 0.5.0 0.6.0; do
  echo "=== $v ==="
  f=$(find /tmp/de_$v -name "*.whl" -o -name "*.tar.gz")
  echo $f
  python3 -c "
import zipfile, tarfile, sys
f = '$f'
if f.endswith('.whl'):
    z = zipfile.ZipFile(f)
    names = [n for n in z.namelist() if n.endswith('_other.py')]
    for n in names:
        content = z.read(n).decode()
        if 'IsHash' in content:
            print('HAS IsHash')
        else:
            print('no IsHash')
else:
    t = tarfile.open(f)
    names = [n for n in t.getnames() if n.endswith('_other.py')]
    for n in names:
        content = t.extractfile(n).read().decode()
        if 'IsHash' in content:
            print('HAS IsHash')
        else:
            print('no IsHash')
"
done
"}
